// Python solution
import sys

def is_prime(p, M):
    s = 4
    for _ in range(0, p - 2):
        s = (s * s) % ((1 << p) - 1)
    return s == 0 or s == 4

if __name__ == '__main__':
    p, M = map(int, input().split())
    print(is_prime(p, M))

