// C++ solution
#include <iostream>

bool is_prime(int p, int M) {
    int s = 4;
    for (int i = 0; i < p - 2; i++) {
        s = (s * s) % ((1 << p) - 1);
    }
    return s == 0 || s == 4;
}

int main() {
    int p, M;
    std::cin >> p >> M;
    std::cout << is_prime(p, M) << std::endl;
    return 0;
}
